MoneyUtil = {}

function MoneyUtil:checkHasMoney(player, type, price, chip)
    if type == Define.Money.DIAMOND then
        return player:getDiamond() >= price
    end
    if type == Define.Money.CHIP then
        chip = chip or 0
        return chip >= price
    end
    if type == Define.Money.KEY then
        return player.yaoshi >= price
    end
    return false
end

function MoneyUtil:consumeMoney(player, uniqueId, type, price, callback)
    if type == Define.Money.DIAMOND then
        PayHelper.payDiamondsSync(player.userId, uniqueId, price, function()
            callback()
        end)
    end
    if type == Define.Money.KEY then
        player:subYaoShi(price)
        callback()
    end
end

return